INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (1, 1, 'Dana darurat berapa bulan', 'Berapa bulan pengeluaran yang ideal disimpan sebagai dana darurat bagi karyawan tetap?', '["Satu bulan sudah cukup", "Tiga sampai enam bulan pengeluaran", "Dua puluh empat bulan minimal"]'::jsonb, 'Tiga sampai enam bulan pengeluaran', 'Dapat PHK mendadak—tabunganmu cukup berapa hari sebenarnya?', 'Aturan umum tiga sampai enam bulan pengeluaran berbeda untuk freelancer dan karyawan tetap. Tidak ada angka universal yang cocok semua situasi.', 'Karyawan tetap butuh lebih sedikit; freelancer tanpa kontrak perlu lebih besar karena pendapatan tidak pasti.', 'Hitung bulan, bukan rasa tenang.', 'Dave Ramsey, Personal Finance Basics') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (2, 1, 'Bayar diri sendiri dulu', 'Urutan menabung yang paling efektif adalah?', '["Sisihkan sisa setelah semua tagihan dibayar", "Alihkan simpanan pertama sebelum pengeluaran lain", "Tabung hanya jika ada bonus"]'::jsonb, 'Alihkan simpanan pertama sebelum pengeluaran lain', 'Gaji masuk, langsung bayar tagihan—tersisa baru nabung, bener?', 'Urutan yang salah membuat tabungan tergantung sisa yang sering bernilai nol di akhir bulan. Membalik urutan mengubah segalanya.', 'Alihkan tabungan pertama sebelum belanja; otomatis memaksa gaya hidup menyesuaikan sisa bukan sebaliknya.', 'Dirimu adalah tagihan pertama.', 'George Clason, The Richest Man in Babylon') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (3, 1, 'Kekayaan bersih', 'Cara paling akurat mengukur posisi finansial seseorang adalah?', '["Lihat saldo rekening saja", "Hitung aset dikurangi semua kewajiban", "Bandingkan gaji dengan teman"]'::jsonb, 'Hitung aset dikurangi semua kewajiban', 'Berapa kekayaanmu jika semua utang dibayar hari ini?', 'Saldo rekening hanya satu sisi cerita. Aset minus kewajiban memberikan gambaran lebih jujur tentang kondisi finansial sesungguhnya.', 'Net worth adalah ukuran kemajuan finansial yang lebih lengkap dari pendapatan atau saldo tabungan saja.', 'Aset minus utang adalah kebenaranmu.', 'Thomas Stanley, The Millionaire Next Door') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (4, 1, 'Audit langganan', 'Langkah pertama mengurangi kebocoran keuangan dari biaya berulang adalah?', '["Batalkan semua langganan tanpa terkecuali", "Tinjau dan batalkan yang tidak memberi nilai aktif", "Pindah ke kartu kredit baru"]'::jsonb, 'Tinjau dan batalkan yang tidak memberi nilai aktif', 'Berapa aplikasi berbayar yang tidak dibuka enam bulan terakhir?', 'Langganan kecil yang tidak dipakai menyedot dompet secara otomatis tanpa terasa besar. Totalnya sering mengejutkan.', 'Biaya berulang perlu ditinjau berkala; batalkan yang tidak memberi nilai nyata untuk membebaskan arus kas.', 'Langganan tidak dipakai, bocor diam-diam.', 'CFPB Consumer Spending Research 2023') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (5, 1, 'Arus kas positif', 'Fondasi paling dasar kesehatan finansial pribadi adalah?', '["Memiliki investasi saham", "Kas masuk lebih besar dari kas keluar setiap bulan", "Memiliki properti minimal satu"]'::jsonb, 'Kas masuk lebih besar dari kas keluar setiap bulan', 'Penghasilan enam juta, pengeluaran enam setengah—bukan masalah gaji?', 'Defisit arus kas bulanan bisa terjadi di semua tingkat pendapatan tanpa pengelolaan sadar. Gaji besar pun bisa minus.', 'Kas masuk lebih besar dari kas keluar adalah fondasi; tanpa itu aset pun bisa tergerus perlahan.', 'Plus kecil setiap bulan itu membangun.', 'Suze Orman, Women and Money') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (6, 1, 'Dana tujuan terpisah', 'Mengapa mencampur dana darurat dan tabungan liburan dalam satu rekening bermasalah?', '["Tidak ada masalah sama sekali", "Mengaburkan berapa uang yang benar-benar bebas dipakai", "Bunga rekening menjadi lebih kecil"]'::jsonb, 'Mengaburkan berapa uang yang benar-benar bebas dipakai', 'Dana darurat dan liburan satu rekening—bisa dibedakan saat panik?', 'Mencampur tujuan dalam satu wadah mengaburkan batas aman. Otak mudah salah hitung saat kebutuhan mendesak datang.', 'Rekening terpisah per tujuan membantu membedakan uang darurat dari dana menyenangkan yang boleh dipakai.', 'Pisahkan tujuan, pisahkan rekening.', 'Richard Thaler, Mental Accounting Theory') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (7, 1, 'Deductible asuransi', 'Memilih premi asuransi rendah dengan deductible tinggi cocok untuk siapa?', '["Semua orang tanpa terkecuali", "Mereka yang punya dana darurat cukup menanggung bagian awal klaim", "Mereka yang sering klaim kecil"]'::jsonb, 'Mereka yang punya dana darurat cukup menanggung bagian awal klaim', 'Premi murah tapi deductible tinggi—itu hemat atau taruhan tersembunyi?', 'Premi rendah tidak berarti perlindungan murah jika kamu tidak siap menanggung bagian awal klaim sendiri.', 'Deductible adalah bagian klaim yang ditanggung sendiri; pilih sesuai kemampuan dana darurat yang tersedia.', 'Deductible tinggi butuh cadangan siap.', 'NAIC Insurance Consumer Guide') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (8, 1, 'Paket komunikasi efisien', 'Cara terbaik memilih paket data dan telepon adalah?', '["Selalu pilih paket terbesar agar tidak kehabisan", "Audit penggunaan aktual dan pilih yang sesuai", "Ganti provider setiap bulan"]'::jsonb, 'Audit penggunaan aktual dan pilih yang sesuai', 'Paket mahal agar semua ada—berapa persen fitur itu terpakai?', 'Membayar kapasitas yang tidak terpakai adalah pemborosan berulang. Selisih kecil tiap bulan jadi besar dalam setahun.', 'Cek penggunaan data dan menit aktual; turunkan ke paket yang cukup untuk kebutuhan nyata.', 'Bayar yang dipakai, bukan yang ditawarkan.', 'Consumer Reports Phone Plan Analysis') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (9, 1, 'Rencana belanja grocery', 'Kebiasaan yang paling efektif mengurangi pembelian impuls di supermarket adalah?', '["Pergi saat lapar agar semangat", "Bawa daftar belanja dan makan dulu sebelum pergi", "Bayar tunai agar tidak boros"]'::jsonb, 'Bawa daftar belanja dan makan dulu sebelum pergi', 'Masuk supermarket tanpa daftar—berapa persen barang sungguh direncanakan?', 'Berbelanja tanpa rencana mendorong impuls yang menggelembungkan tagihan jauh di atas kebutuhan nyata.', 'Daftar belanja dan perut kenyang mengurangi pembelian impuls yang menggelembungkan tagihan grocery bulanan.', 'Daftar belanja adalah pagar supermarket.', 'Cornell Food Lab, Wansink Studies') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (10, 1, 'Barang bekas bernilai', 'Alasan utama barang bekas berkualitas sering lebih efisien biaya adalah?', '["Selalu berarti murah dan berkualitas rendah", "Depresiasi besar di awal membuat harga lebih wajar dari fungsinya", "Tidak ada garansi jadi lebih murah"]'::jsonb, 'Depresiasi besar di awal membuat harga lebih wajar dari fungsinya', 'Produk bekas setengah harga—itu nekat atau matematika sederhana?', 'Barang bekas kondisi baik memberikan nilai serupa dengan harga jauh di bawah baru. Depresiasi bekerja untuk pembelinya.', 'Depresiasi besar di tahun pertama membuat produk bekas berkualitas sering lebih efisien secara biaya nyata.', 'Bekas bukan murahan, tapi cerdas.', 'Ramit Sethi, I Will Teach You Rich') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (11, 2, 'Jangkar harga', 'Mengapa harga coret di toko sering membuat diskon terasa lebih besar dari kenyataan?', '["Karena diskonnya memang selalu nyata dan besar", "Otak menilai harga baru relatif terhadap referensi awal", "Karena penjual selalu jujur"]'::jsonb, 'Otak menilai harga baru relatif terhadap referensi awal', 'Harga coret dua ratus, sekarang seratus—seratus itu murah atau ilusi?', 'Harga pertama yang terlihat mempengaruhi penilaian apakah harga berikutnya terasa murah atau mahal secara psikologis.', 'Anchor pricing mengeksploitasi kecenderungan otak menilai relatif terhadap referensi awal bukan nilai sesungguhnya.', 'Harga pertama adalah jangkar pikiran.', 'Kahneman, Thinking Fast and Slow') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (12, 2, 'Waktu sebagai modal', 'Mengapa antre dua jam untuk diskon lima ribu sering tidak menguntungkan?', '["Karena waktu gratis dan tidak bernilai", "Biaya peluang waktu sering melebihi nilai diskon yang didapat", "Antre selalu hemat lebih banyak"]'::jsonb, 'Biaya peluang waktu sering melebihi nilai diskon yang didapat', 'Gratis katanya—tapi dua jam antre untuk diskon lima ribu?', 'Waktu adalah aset terbatas yang sering tidak dihargai saat mengejar penghematan kecil. Waktumu bernilai.', 'Biaya peluang waktu perlu dihitung; aktivitas bermakna atau produktif lain mungkin lebih bernilai dari diskon tersebut.', 'Waktu habis tidak bisa diisi lagi.', 'Opportunity Cost Theory, Economics') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (13, 2, 'Warisan pola pikir uang', 'Dari mana sebagian besar keyakinan tentang uang terbentuk pertama kali?', '["Dari sekolah formal dan buku teks", "Dari keluarga dan pengalaman masa kecil", "Dari iklan televisi semata"]'::jsonb, 'Dari keluarga dan pengalaman masa kecil', 'Orang tua bilang uang itu susah—pola pikir itu menular juga?', 'Kepercayaan tentang uang yang dipelajari dari keluarga sering mengendalikan keputusan tanpa disadari. Bisa membantu atau menghambat.', 'Money scripts dari masa kecil membentuk kebiasaan dewasa; mengenalinya adalah langkah awal untuk mengubahnya.', 'Nilai uang dipelajari, bisa diubah.', 'Brad Klontz, Mind Over Money') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (14, 2, 'Menunda kepuasan', 'Kemampuan menunda hadiah kecil berkaitan dengan apa dalam jangka panjang?', '["Tidak ada korelasi sama sekali", "Kesehatan finansial yang lebih stabil secara historis", "Kebahagiaan yang lebih rendah"]'::jsonb, 'Kesehatan finansial yang lebih stabil secara historis', 'Satu sekarang vs dua nanti—itu uji kecerdasan atau pengendalian diri?', 'Kemampuan menunda kepuasan berkorelasi dengan kesehatan finansial jangka panjang yang lebih baik dalam banyak studi.', 'Menunda konsumsi dan menginvestasikan selisihnya membiarkan kompaun bekerja jauh lebih maksimal dari waktu ke waktu.', 'Tunda sekarang, panen lebih besar nanti.', 'Stanford Marshmallow Experiment 1972') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (15, 2, 'Kelelahan memutuskan', 'Mengapa belanja impuls lebih sering terjadi di malam hari?', '["Karena harga lebih murah malam hari", "Energi kognitif terkuras seharian membuat pertahanan diri melemah", "Karena promosi hanya malam hari"]'::jsonb, 'Energi kognitif terkuras seharian membuat pertahanan diri melemah', 'Banyak keputusan seharian—kenapa checkout impuls sering terjadi malam?', 'Otak memiliki kapasitas terbatas untuk memutuskan setiap hari. Keputusan terus-menerus menguras kualitas pilihan berikutnya.', 'Decision fatigue mengurangi kualitas pilihan finansial; sederhanakan keputusan rutin agar kapasitas kognitif terjaga.', 'Kelelahan keputusan membuka dompet lebar.', 'Baumeister, Ego Depletion Research') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (16, 2, 'Tekanan sosial belanja', 'Keputusan belanja yang didorong keinginan diterima kelompok biasanya menghasilkan?', '["Kepuasan jangka panjang yang tinggi", "Pengeluaran tidak dianggarkan yang menguras lebih dari perkiraan", "Penghematan otomatis karena malu"]'::jsonb, 'Pengeluaran tidak dianggarkan yang menguras lebih dari perkiraan', 'Nongkrong padahal tabungan tipis—takut dianggap pelit atau sungguh menikmati?', 'Keputusan keuangan sering dibentuk keinginan diterima sosial daripada kebutuhan nyata dan anggaran yang tersedia.', 'Pengeluaran sosial yang tidak dianggarkan menguras lebih dari perkiraan; tetapkan anggaran hiburan realistis terlebih dahulu.', 'Hubungan baik tak perlu dompet tipis.', 'Robert Cialdini, Influence') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (17, 2, 'Ilusi kenaikan gaji', 'Kenaikan gaji tidak mengubah posisi finansial jika apa yang terjadi?', '["Pajak turun bersamaan", "Gaya hidup ikut naik menyerap seluruh kenaikan", "Investasi otomatis ditambah"]'::jsonb, 'Gaya hidup ikut naik menyerap seluruh kenaikan', 'Gaji naik satu juta—setelah inflasi dan gaya hidup baru, tersisa berapa?', 'Kenaikan penghasilan yang langsung diserap lifestyle tidak mengubah posisi finansial secara bermakna. Jarak tetap sama.', 'Sisihkan dulu dari kenaikan sebelum gaya hidup baru terbentuk; kebiasaan baru sulit dihapus setelah terbentuk.', 'Naik gaji bukan izin upgrade gaya hidup.', 'Morgan Housel, Psychology of Money') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (18, 2, 'Efek decoy harga', 'Mengapa toko sering menempatkan produk paling mahal di posisi paling terlihat?', '["Agar cepat terjual duluan", "Membuat produk harga tengah terlihat lebih wajar dan masuk akal", "Itu hanya kebetulan tata letak"]'::jsonb, 'Membuat produk harga tengah terlihat lebih wajar dan masuk akal', 'Produk premium di etalase depan—biar yang tengah terasa wajar?', 'Penataan produk dirancang menggunakan jangkar harga untuk mempengaruhi persepsi nilai tanpa disadari pembeli.', 'Decoy effect menempatkan pilihan tengah lebih menarik dengan membandingkannya ke versi ekstrem yang lebih mahal.', 'Pilihan tengah bisa sengaja dirancang.', 'Dan Ariely, Predictably Irrational') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (19, 2, 'Lomba pengeluaran sosial', 'Pengeluaran untuk mempertahankan status relatif dibanding tetangga disebut apa?', '["Investasi reputasi yang sehat", "Keeping up with the Joneses yang tidak ada garis finishnya", "Strategi branding pribadi"]'::jsonb, 'Keeping up with the Joneses yang tidak ada garis finishnya', 'Lihat rumah tetangga baru—langsung kepikiran pindah juga?', 'Perbandingan sosial mendorong pengeluaran untuk mempertahankan status relatif bukan kebutuhan absolut yang sesungguhnya.', 'Lomba konsumsi sosial tidak memiliki titik akhir; selalu ada yang lebih baru dan lebih mahal di sekitar.', 'Lomba pengeluaran tak ada garis finish.', 'Veblen, Theory of the Leisure Class') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (20, 2, 'Mindset kelimpahan', 'Apa yang membedakan mindset kelangkaan dari mindset kelimpahan dalam pengambilan keputusan?', '["Hanya perbedaan jumlah harta saja", "Kelangkaan membuat jangka pendek dominan; kelimpahan membuka pilihan lebih luas", "Keduanya identik hasilnya"]'::jsonb, 'Kelangkaan membuat jangka pendek dominan; kelimpahan membuka pilihan lebih luas', 'Merasa tidak pernah cukup meski penghasilan naik—masalah angka atau pikiran?', 'Mindset kelangkaan memengaruhi cara otak memproses peluang dan risiko finansial. Bukan soal jumlah, tapi persepsi.', 'Tekanan kelangkaan pikiran membuat keputusan jangka pendek mendominasi; pergeseran mindset membuka pilihan lebih strategis.', 'Pola pikir membentuk pola dompet.', 'Mullainathan & Shafir, Scarcity') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (21, 3, 'Rasio P/E saham', 'Rasio P/E yang sangat tinggi dibanding industri biasanya mencerminkan apa?', '["Saham pasti murah dan layak dibeli", "Pasar membayar premium untuk ekspektasi pertumbuhan lebih tinggi", "Perusahaan tidak punya kompetitor"]'::jsonb, 'Pasar membayar premium untuk ekspektasi pertumbuhan lebih tinggi', 'Saham mahal di harga dua ribu—mahal dibanding apa sebenarnya?', 'Harga saham sendiri tidak bermakna tanpa dibandingkan kemampuan perusahaan menghasilkan laba aktual yang nyata.', 'P/E membagi harga saham dengan laba per lembar; mencerminkan berapa kali laba yang dibayar pasar.', 'Harga tanpa laba hanyalah angka kosong.', 'Benjamin Graham, The Intelligent Investor') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (22, 3, 'Pemecahan saham', 'Stock split mengubah apa pada portofoliomu secara fundamental?', '["Nilai total kepemilikanmu turun setengah", "Jumlah lembar bertambah namun nilai total tetap sama", "Kamu otomatis dapat dividen lebih besar"]'::jsonb, 'Jumlah lembar bertambah namun nilai total tetap sama', 'Stock split membuat harga turun setengah—rugi atau apa yang terjadi?', 'Pemecahan saham mengubah jumlah lembar dan harga proporsional tanpa mengubah nilai total kepemilikan yang ada.', 'Total nilai porsi tetap sama; split umumnya meningkatkan likuiditas karena harga per lembar lebih terjangkau investor kecil.', 'Split harga, kepemilikan total tetap.', 'NYSE Education, Stock Split Guide') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (23, 3, 'Nilai vs pertumbuhan', 'Saham value dan growth biasanya berbeda dalam hal apa?', '["Tidak ada perbedaan sama sekali", "Value murah relatif fundamental; growth bayar premium proyeksi masa depan", "Hanya beda nama saja"]'::jsonb, 'Value murah relatif fundamental; growth bayar premium proyeksi masa depan', 'Saham murah P/E vs tumbuh cepat—mana lebih aman jangka panjang?', 'Kedua pendekatan memiliki musim berbeda; value sering unggul pemulihan, growth di ekspansi likuiditas tinggi.', 'Value investing mencari diskon fundamental; growth investing membayar premium untuk ekspansi masa depan yang diproyeksikan.', 'Nilai dan pertumbuhan silih berganti unggul.', 'Fama French, Factor Research Papers') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (24, 3, 'Dollar cost averaging', 'Strategi DCA paling membantu mengatasi risiko apa?', '["Risiko perusahaan bangkrut", "Risiko membeli semua di harga puncak sekaligus", "Risiko inflasi jangka panjang"]'::jsonb, 'Risiko membeli semua di harga puncak sekaligus', 'Beli terus saat turun dan naik—bisa mengalahkan tebak waktu pasar?', 'Investasi rutin jumlah tetap mengurangi dampak membeli di puncak secara rata-rata matematika dari waktu ke waktu.', 'DCA meratakan harga beli dari waktu ke waktu tanpa memprediksi kapan titik terendah terjadi.', 'Rutin kecil lebih kuat dari tebakan.', 'Vanguard DCA vs Lump Sum Study') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (25, 3, 'Analisis fundamental', 'Analisis fundamental saham berfokus pada apa?', '["Pola grafik harga harian", "Laporan keuangan dan kemampuan bisnis menghasilkan arus kas", "Jumlah follower media sosial perusahaan"]'::jsonb, 'Laporan keuangan dan kemampuan bisnis menghasilkan arus kas', 'Saham viral tapi laporan keuangannya belum pernah dibuka—itu bukan riset.', 'Membaca laporan laba rugi dan arus kas membantu menilai bisnis nyata di balik kode saham tersebut.', 'Fundamental mencakup pendapatan, margin, utang, dan arus kas; dasar penilaian intrinsik selain harga pasar.', 'Laporan keuangan adalah bahasa bisnis.', 'Philip Fisher, Common Stocks Uncommon Profits') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (26, 3, 'Beta dan volatilitas', 'Saham dengan beta lebih dari satu artinya apa?', '["Lebih stabil dari pasar secara umum", "Bergerak lebih besar dari indeks saat pasar bergerak", "Pasti memberikan return lebih tinggi"]'::jsonb, 'Bergerak lebih besar dari indeks saat pasar bergerak', 'Saham defensif—tapi kalau pasar gerak dua persen sehari, ikut berapa?', 'Beta mengukur seberapa banyak saham bergerak dibandingkan pasar; berguna memahami risiko relatif terhadap indeks.', 'Beta di atas satu lebih bergerak dari indeks; di bawah satu lebih stabil dari rata-rata pasar.', 'Beta tinggi, naik turun lebih keras.', 'CAPM Model, Sharpe and Lintner') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (27, 3, 'Rotasi sektor', 'Fase ekspansi ekonomi biasanya menguntungkan sektor apa?', '["Sektor defensif seperti utilitas dan konsumer staples", "Sektor siklikal seperti konsumer diskresioner dan teknologi", "Sektor keuangan tidak pernah berubah"]'::jsonb, 'Sektor siklikal seperti konsumer diskresioner dan teknologi', 'Sektor unggul tahun lalu sering bukan yang unggul tahun ini—ada pola?', 'Siklus ekonomi menguntungkan sektor berbeda di fase ekspansi, puncak, kontraksi, dan pemulihan secara bergantian.', 'Memahami fase ekonomi membantu menilai sektor yang lebih mungkin terdorong tanpa menjamin ketepatan waktu.', 'Siklus menggeser bintang antar sektor.', 'Sam Stovall, S&P Sector Rotation') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (28, 3, 'Stop loss disiplin', 'Menetapkan stop loss sebelum membeli saham bertujuan utama untuk apa?', '["Memaksimalkan return jangka pendek", "Mengotomatiskan keputusan keluar agar emosi tidak mendikte saat rugi", "Menghindari pajak capital gain"]'::jsonb, 'Mengotomatiskan keputusan keluar agar emosi tidak mendikte saat rugi', 'Menetapkan batas rugi sebelum beli—itu takut atau strategi risiko?', 'Stop loss mengotomatiskan keputusan keluar agar emosi tidak mendikte saat posisi berada di zona merah.', 'Tanpa batas rugi tertulis, aversi rugi sering membuat investor mempertahankan posisi buruk terlalu lama.', 'Batasi rugi sebelum emosi berkuasa.', 'Jesse Livermore, Stock Operator') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (29, 3, 'Risiko konsentrasi', 'Menempatkan tiga puluh persen portofolio di satu saham meningkatkan risiko apa?', '["Tidak ada risiko tambahan", "Dampak kejadian spesifik perusahaan ke total portofolio sangat besar", "Pajak otomatis lebih tinggi"]'::jsonb, 'Dampak kejadian spesifik perusahaan ke total portofolio sangat besar', 'Satu saham sepuluh persen portofolio—berita divisi itu bisa merusak berapa?', 'Posisi besar satu emiten memperbesar dampak kejadian spesifik perusahaan ke portofolio secara keseluruhan drastis.', 'Konsentrasi meningkatkan return potensi tapi juga memperbesar drawdown dari risiko spesifik yang tidak sistemik.', 'Posisi besar, dampak perusahaan penuh.', 'Markowitz, Modern Portfolio Theory') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (30, 3, 'Aktif vs pasif', 'Mengapa mayoritas manajer aktif underperform indeks dalam jangka panjang?', '["Karena mereka tidak bekerja keras", "Biaya pengelolaan aktif mengikis return relatif terhadap indeks pasif", "Indeks selalu dimanipulasi naik"]'::jsonb, 'Biaya pengelolaan aktif mengikis return relatif terhadap indeks pasif', 'Mayoritas manajer aktif gagal kalahkan indeks jangka panjang—mengejutkan?', 'Biaya pengelolaan aktif dan kesulitan konsisten memilih saham membuat banyak fund aktif tertinggal indeks.', 'SPIVA melaporkan mayoritas manajer aktif underperform indeks benchmark setelah biaya dalam jangka sepuluh tahun.', 'Biaya aktif membebani return jangka panjang.', 'SPIVA Active vs Passive Report') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (31, 4, 'Obligasi zero coupon', 'Obligasi zero coupon memberikan return dari mana jika tidak ada pembayaran bunga berkala?', '["Dari dividen yang dibagikan setiap kuartal", "Dari selisih harga beli diskon ke nilai pari saat jatuh tempo", "Dari kenaikan harga pasar saham"]'::jsonb, 'Dari selisih harga beli diskon ke nilai pari saat jatuh tempo', 'Obligasi tanpa bunga bulanan tapi bisa untung—bagaimana itu mungkin?', 'Obligasi zero coupon dibeli di bawah nilai pari dan dilunasi di nilai penuh saat jatuh tempo.', 'Tidak ada kupon berkala; return berasal dari selisih harga beli diskon ke nilai pari jatuh tempo.', 'Beli murah, terima penuh di akhir.', 'Frank Fabozzi, Fixed Income Analysis') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (32, 4, 'Obligasi konversi', 'Investor menerima kupon lebih rendah pada obligasi konversi sebagai kompensasi apa?', '["Risiko lebih tinggi tanpa ada manfaat", "Opsi mengubah obligasi menjadi saham saat kondisi menguntungkan", "Bunga yang dijamin naik tiap tahun"]'::jsonb, 'Opsi mengubah obligasi menjadi saham saat kondisi menguntungkan', 'Obligasi yang bisa jadi saham—itu utang atau modal sendiri?', 'Obligasi konversi menggabungkan sifat utang dan ekuitas; memberikan opsi berubah menjadi saham pada syarat tertentu.', 'Investor mendapat kupon lebih rendah sebagai kompensasi opsi konversi; menarik jika saham diperkirakan naik signifikan.', 'Konversi: bunga rendah, opsi pertumbuhan.', 'BIS Research Convertible Securities') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (33, 4, 'Tangga obligasi', 'Strategi bond ladder mengatasi risiko apa pada portofolio obligasi?', '["Risiko inflasi jangka panjang", "Risiko reinvestasi di satu titik suku bunga sekaligus", "Risiko gagal bayar penerbit"]'::jsonb, 'Risiko reinvestasi di satu titik suku bunga sekaligus', 'Semua obligasi jatuh tempo satu waktu—risiko reinvestasi datang sekaligus?', 'Menyebar jatuh tempo di beberapa tahun mengurangi risiko reinvestasi di satu titik suku bunga tertentu.', 'Laddering memastikan porsi jatuh tempo tiap periode; kas masuk bisa diinvestasikan kembali sesuai suku berlaku saat itu.', 'Sebarkan jatuh tempo, atur arus kas.', 'FINRA Bond Ladder Strategy Guide') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (34, 4, 'Yield riil vs nominal', 'Yield riil obligasi dihitung dengan cara apa?', '["Yield nominal ditambah inflasi", "Yield nominal dikurangi inflasi", "Yield nominal dibagi dua"]'::jsonb, 'Yield nominal dikurangi inflasi', 'Kupon enam persen di inflasi tujuh persen—menang atau rugi riil?', 'Suku bunga nominal tidak sama dengan daya beli nyata. Inflasi adalah pengurang diam-diam yang sering diabaikan.', 'Real yield adalah nominal dikurangi inflasi; negatif berarti daya beli berkurang meski nominal masuk.', 'Nominal positif bisa riil negatif.', 'Fisher Effect, Irving Fisher Economics') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (35, 4, 'Credit spread', 'Pelebaran credit spread obligasi korporat menandakan apa di pasar?', '["Pasar semakin optimis pada ekonomi", "Kekhawatiran meningkat tentang kemampuan bayar emiten", "Inflasi segera turun"]'::jsonb, 'Kekhawatiran meningkat tentang kemampuan bayar emiten', 'Obligasi korporat berbunga lebih tinggi dari pemerintah—selisihnya apa artinya?', 'Selisih yield adalah kompensasi risiko ketidakpastian kemampuan bayar emiten korporat dibanding pemerintah yang lebih aman.', 'Credit spread melebar saat pasar khawatir kemampuan bayar; menyempit saat kepercayaan membaik dan likuiditas lancar.', 'Selisih yield adalah harga risiko bayar.', 'CFA Institute Fixed Income Curriculum') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (36, 4, 'Callable bond', 'Risiko utama investor pada callable bond adalah apa?', '["Risiko penerbit tidak membayar kupon", "Risiko reinvestasi saat obligasi dilunasi lebih awal di suku rendah", "Risiko harga selalu naik terus"]'::jsonb, 'Risiko reinvestasi saat obligasi dilunasi lebih awal di suku rendah', 'Emiten bisa lunasi obligasimu lebih awal—itu kabar bagus atau tidak?', 'Callable memberikan hak penerbit melunasi lebih awal saat bunga turun dan refinancing lebih menguntungkan mereka.', 'Investor menghadapi risiko reinvestasi; pelunasan awal terjadi justru saat return reinvestasi lebih rendah dari kupon asal.', 'Callable baik bagi penerbit, waspada investor.', 'Investopedia Callable Bond Analysis') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (37, 4, 'Sukuk obligasi syariah', 'Perbedaan mendasar sukuk dengan obligasi konvensional adalah?', '["Sukuk memberikan bunga lebih tinggi", "Sukuk mewakili kepemilikan aset nyata bukan klaim utang berbunga", "Sukuk hanya untuk pemerintah"]'::jsonb, 'Sukuk mewakili kepemilikan aset nyata bukan klaim utang berbunga', 'Sukuk disebut obligasi syariah—bedanya mendasar di mana?', 'Sukuk tidak membayar bunga tetapi memberikan bagi hasil atau imbal berbasis kepemilikan aset yang nyata.', 'Sukuk mewakili kepemilikan parsial aset nyata atau aliran manfaat bukan klaim utang berbunga biasa.', 'Aset nyata mendasari, bukan utang berbunga.', 'IIFM Sukuk Database Report') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (38, 4, 'Likuiditas obligasi korporat', 'Risiko likuiditas obligasi korporat kecil paling terasa saat apa?', '["Saat kupon dibayarkan rutin", "Saat investor perlu menjual cepat sebelum jatuh tempo", "Saat suku bunga turun"]'::jsonb, 'Saat investor perlu menjual cepat sebelum jatuh tempo', 'Obligasi korporat kecil susah dijual saat butuh uang—tidak terlihat di kupon.', 'Obligasi yang jarang diperdagangkan susah dijual dengan harga wajar ketika butuh likuiditas cepat secara mendesak.', 'Likuiditas rendah memperlebar bid-ask spread dan memaksa haircut besar jika harus keluar sebelum jatuh tempo.', 'Obligasi sunyi, keluar bisa mahal.', 'BIS Bond Market Liquidity Paper') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (39, 4, 'Fund obligasi vs langsung', 'Perbedaan utama membeli obligasi langsung vs reksa dana obligasi adalah?', '["Reksa dana lebih aman dari obligasi langsung", "Obligasi langsung memberikan kepastian arus kas dan pari; fund berfluktuasi harian", "Tidak ada perbedaan sama sekali"]'::jsonb, 'Obligasi langsung memberikan kepastian arus kas dan pari; fund berfluktuasi harian', 'Obligasi langsung vs reksa dana obligasi—lebih sesuai yang mana?', 'Obligasi langsung memberikan kepastian arus kas dan pari saat maturasi; fund obligasi berfluktuasi nilai setiap hari.', 'Fund obligasi tidak memiliki jatuh tempo pasti; investor menerima return pasar bukan janji pari di akhir.', 'Fund cair, obligasi langsung berkepastian.', 'Vanguard Individual Bonds vs Fund') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (40, 4, 'Tenor dan sensitivitas suku bunga', 'Mengapa obligasi tenor panjang lebih sensitif terhadap perubahan suku bunga?', '["Karena kuponnya lebih besar", "Jarak lebih panjang memperbesar dampak perubahan diskonto ke harga saat ini", "Penerbit lebih sering gagal bayar"]'::jsonb, 'Jarak lebih panjang memperbesar dampak perubahan diskonto ke harga saat ini', 'Tenor panjang imbalannya besar—tapi goyangannya juga besar kenapa?', 'Investor mengikat uang lebih lama dengan tenor panjang sehingga kompensasi risiko suku bunga lebih besar.', 'Durasi panjang meningkatkan volatilitas harga walaupun kupon tetap terasa stabil di laporan.', 'Panjang tenor, guncangan bunga lebih keras.', 'Fabozzi, Duration and Convexity') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (41, 5, 'ETF leverage harian', 'Mengapa ETF leverage tiga kali tidak cocok untuk investasi jangka panjang?', '["Biayanya terlalu mahal saja", "Volatility decay menggerus return saat pasar naik-turun meski tren naik", "Regulator melarang jangka panjang"]'::jsonb, 'Volatility decay menggerus return saat pasar naik-turun meski tren naik', 'ETF tiga kali leverage naik tiga kali—turun juga tiga kali?', 'ETF leverage dirancang untuk return harian berlipatganda bukan jangka panjang karena efek rebalancing harian yang merusak.', 'Volatility decay menggerus return jangka panjang ETF leverage saat pasar bergerak naik-turun meski tren ke atas.', 'Leverage harian tidak cocok jangka panjang.', 'ProShares Leveraged ETF Disclosure') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (42, 5, 'ETF inverse', 'ETF inverse paling cocok digunakan untuk apa?', '["Investasi jangka panjang pasif", "Hedging jangka pendek terhadap penurunan pasar", "Menggantikan obligasi dalam portofolio"]'::jsonb, 'Hedging jangka pendek terhadap penurunan pasar', 'ETF yang untung saat pasar turun—asuransi atau taruhan?', 'ETF inverse dirancang bergerak berlawanan indeks tertentu dan sering bermasalah jika dipegang dalam waktu lama.', 'Seperti leverage, rebalancing harian menyebabkan drift dari ekspektasi; cocok untuk hedging jangka pendek saja.', 'Inverse: pagar harian bukan permanen.', 'SEC Investor Bulletin Inverse ETF') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (43, 5, 'Smart beta faktor', 'Smart beta ETF berbeda dari ETF indeks biasa dalam hal apa?', '["Tidak ada perbedaan sama sekali", "Menyaring atau mengbobot berdasarkan faktor sistematis bukan hanya market cap", "Selalu memberikan return lebih tinggi"]'::jsonb, 'Menyaring atau mengbobot berdasarkan faktor sistematis bukan hanya market cap', 'ETF faktor bukan market cap—lebih pintar atau lebih rumit?', 'Smart beta menyaring atau mengbobot berdasarkan faktor seperti nilai, momentum, atau kualitas secara sistematis terukur.', 'Smart beta antara aktif dan pasif; biaya lebih rendah dari aktif tapi lebih tinggi dari indeks luas biasa.', 'Faktor ada buktinya, bukan sihir.', 'Fama French Three Factor Model') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (44, 5, 'ETF ESG', 'Tantangan utama investor yang ingin berinvestasi lewat ETF ESG adalah?', '["Tidak tersedia di bursa manapun", "Definisi ESG berbeda antar provider dan bukti return masih campuran", "ESG selalu return lebih rendah pasti"]'::jsonb, 'Definisi ESG berbeda antar provider dan bukti return masih campuran', 'Investasi sesuai nilai lingkungan—return-nya benar-benar tidak kalah?', 'ETF ESG menyaring perusahaan berdasarkan kriteria lingkungan, sosial, dan tata kelola selain nilai finansial murni.', 'Bukti return ESG masih campuran; biaya dan kriteria inklusi aset bervariasi secara signifikan antarprovider.', 'ESG: nilai dan return bisa seiring.', 'MSCI ESG Research 2023 Report') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (45, 5, 'ETF komoditas dan roll cost', 'ETF komoditas berbasis futures sering mengalami pengurangan return karena apa?', '["Pajak tinggi pada komoditas", "Roll cost saat kontrak futures lebih mahal dari harga spot", "Manajemen aktif terlalu sering"]'::jsonb, 'Roll cost saat kontrak futures lebih mahal dari harga spot', 'Harga emas naik—apakah ETF emas bergerak persis sama?', 'ETF komoditas bisa tracking harga fisik atau futures dengan perbedaan perilaku yang penting dipahami investor.', 'ETF futures komoditas menderita roll cost saat kontrak baru lebih mahal dari harga spot saat ini.', 'Komoditas ETF bukan harga fisik langsung.', 'S&P GSCI Commodity Index Docs') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (46, 5, 'ETF obligasi vs obligasi langsung', 'Bagaimana ETF obligasi berbeda dari obligasi langsung dalam hal harga?', '["ETF obligasi harganya tetap seperti deposito", "ETF obligasi bergerak naik-turun harian mengikuti pasar", "ETF obligasi tidak dipengaruhi suku bunga"]'::jsonb, 'ETF obligasi bergerak naik-turun harian mengikuti pasar', 'Reksa obligasi naik turun harian—padahal isinya kupon tetap?', 'ETF obligasi memberikan likuiditas dan diversifikasi surat utang dalam satu unit yang diperdagangkan di bursa.', 'Pergerakan harga ETF obligasi dipengaruhi suku bunga dan credit spread; berbeda dari obligasi langsung yang dipegang maturasi.', 'ETF obligasi cair tapi tetap bergerak.', 'iShares Bond ETF Research Center') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (47, 5, 'Efisiensi pajak ETF', 'Mengapa ETF umumnya lebih efisien pajak dibanding reksa dana konvensional?', '["ETF selalu bebas pajak di semua negara", "Mekanisme in-kind redemption menghindari distribusi capital gain", "ETF tidak memiliki keuntungan pajak"]'::jsonb, 'Mekanisme in-kind redemption menghindari distribusi capital gain', 'ETF lebih hemat pajak dari reksa dana biasa—mekanismenya kenapa?', 'Mekanisme in-kind creation redemption ETF sering menghindari distribusi capital gain yang terkena pajak bagi investor.', 'Investor ETF umumnya hanya kena pajak saat menjual unit sendiri, bukan saat fund melakukan rebalancing internal.', 'ETF hemat pajak lewat mekanisme unik.', 'IRS ETF Tax Treatment Guide') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (48, 5, 'Konsentrasi di indeks besar', 'Risiko tersembunyi ETF indeks berbobot market cap adalah?', '["Terlalu banyak sekuritas yang dimasukkan", "Lima atau sepuluh saham terbesar bisa mendominasi bobot secara signifikan", "Tidak ada risiko konsentrasi sama sekali"]'::jsonb, 'Lima atau sepuluh saham terbesar bisa mendominasi bobot secara signifikan', 'Lima saham teknologi isi dua puluh persen indeks—itu diversifikasi?', 'Indeks berbobot kapital bisa sangat terkonsentrasi di beberapa nama besar yang mendominasi pergerakannya sehari-hari.', 'Investor perlu sadar konsentrasi teratas indeks; diversifikasi tambahan bisa lewat faktor berbeda atau regional lain.', 'Indeks besar bukan diversifikasi merata.', 'Morningstar Index Concentration Research') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (49, 5, 'Hedging mata uang di ETF', 'ETF global dengan currency hedging cocok untuk investor yang ingin apa?', '["Eksposur penuh terhadap fluktuasi kurs", "Hanya eksposur aset tanpa taruhan pada pergerakan mata uang", "Return tertinggi tanpa biaya tambahan"]'::jsonb, 'Hanya eksposur aset tanpa taruhan pada pergerakan mata uang', 'ETF global unhedged—return bagus tapi dolar menguat, rugi konversi?', 'Hedging mata uang melindungi return dari fluktuasi kurs namun menambah biaya dan kompleksitas pada ETF.', 'Hedged ETF cocok jika ingin eksposur aset saja tanpa taruhan kurs; unhedged jika sebaliknya diinginkan.', 'Kurs bisa makan return luar negeri.', 'State Street Hedged vs Unhedged') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (50, 5, 'Bahaya rotasi ETF', 'Investor yang sering pindah ETF mengikuti performa terbaik biasanya menghasilkan apa?', '["Return lebih tinggi dari yang diam", "Return lebih rendah karena biaya dan pajak menggerus lebih dari diam", "Diversifikasi lebih baik"]'::jsonb, 'Return lebih rendah karena biaya dan pajak menggerus lebih dari diam', 'Pindah ETF terus cari performa terbaik—strategi atau insecurity?', 'Berpindah ETF sering menghasilkan biaya transaksi dan pajak yang menggerus return lebih dari sekadar diam.', 'Performance chasing memotong return investor di bawah return fund itu sendiri secara historis konsisten.', 'Diam di ETF sering lebih menguntungkan.', 'DALBAR QAIB Investor Behavior Study') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (51, 6, 'Dividend aristocrats', 'Apa yang membedakan dividend aristocrats dari saham dividen biasa?', '["Hanya yield-nya yang lebih tinggi", "Rekam jejak menaikkan dividen minimal dua puluh lima tahun berturut-turut", "Selalu dari sektor teknologi"]'::jsonb, 'Rekam jejak menaikkan dividen minimal dua puluh lima tahun berturut-turut', 'Perusahaan naikkan dividen dua puluh lima tahun berturut—itu langka?', 'Dividend aristocrats memiliki rekam jejak menaikkan payout konsisten bahkan melewati berbagai resesi dan krisis besar.', 'Konsistensi kenaikan dividen mencerminkan manajemen kas disiplin dan model bisnis yang tahan terhadap berbagai siklus.', 'Konsistensi naikkan dividen tanda bisnis sehat.', 'S&P Dividend Aristocrats Index') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (52, 6, 'Payout ratio sehat', 'Payout ratio obligasi di atas seratus persen menandakan apa?', '["Perusahaan sangat sehat dan murah hati", "Dividen kemungkinan dibayar dari utang atau cadangan kas", "Laba tumbuh sangat cepat"]'::jsonb, 'Dividen kemungkinan dibayar dari utang atau cadangan kas', 'Dividen besar tapi laba kecil—baik hati atau lampu merah?', 'Payout ratio mengukur berapa persen laba didistribusikan sebagai dividen; terlalu tinggi bisa tidak berkelanjutan lama.', 'Rasio di atas seratus persen berarti dividen dari utang atau cadangan; sinyal waspada yang serius.', 'Dividen besar dari laba tipis, waspada.', 'CFA Institute Dividend Policy Analysis') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (53, 6, 'Dividen tumbuh konsisten', 'Strategi dividend growth investing mengutamakan apa di atas yield tinggi saat ini?', '["Saham dengan yield tertinggi di pasar", "Pertumbuhan dividen konsisten yang menghasilkan yield on cost tinggi di masa depan", "Dividen special sekali besar"]'::jsonb, 'Pertumbuhan dividen konsisten yang menghasilkan yield on cost tinggi di masa depan', 'Dividen kecil tapi naik sepuluh persen tiap tahun—dalam dua puluh tahun?', 'Pertumbuhan dividen konsisten bisa memberikan yield on cost jauh lebih tinggi dari harga beli awal dahulu.', 'Investor jangka panjang lebih peduli pertumbuhan dividen masa depan daripada yield absolut saat pertama membeli.', 'Kecil sekarang bisa besar jika tumbuh.', 'Ned Davis Research DGI Strategy') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (54, 6, 'Dividen saham vs tunai', 'Dividen saham berbeda dari dividen tunai dalam hal apa yang fundamental?', '["Dividen saham selalu lebih menguntungkan", "Dividen saham tidak menambah nilai kepemilikan; jumlah lembar lebih banyak tapi per lembar lebih kecil", "Dividen saham tidak dikenai pajak"]'::jsonb, 'Dividen saham tidak menambah nilai kepemilikan; jumlah lembar lebih banyak tapi per lembar lebih kecil', 'Dividen bukan tunai tapi saham—kamu kaya atau lebih banyak kertas?', 'Dividen saham menambah lembar yang dipegang tapi mengencerkan kepemilikan total dan nilai per lembar secara proporsional.', 'Tidak ada nilai tambah langsung; total kepemilikan sama tapi terbagi ke lebih banyak lembar beredar.', 'Lebih banyak lembar bukan lebih kaya.', 'Brealey Myers Principles Corporate Finance') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (55, 6, 'Dividend trap', 'Dividend trap terjadi ketika yield tinggi disebabkan oleh apa?', '["Pertumbuhan laba yang sangat cepat", "Harga saham turun tajam sehingga perhitungan yield terlihat besar", "Perusahaan baru menaikkan payout"]'::jsonb, 'Harga saham turun tajam sehingga perhitungan yield terlihat besar', 'Yield tinggi dan menggoda—tapi saham merah terus tiga tahun?', 'Dividend trap terjadi ketika yield tinggi karena harga turun bukan karena payout meningkat secara fundamental.', 'Total return termasuk apresiasi harga; dividen besar tidak mengompensasi kehilangan kapital besar yang terjadi konsisten.', 'Yield tinggi bisa menutupi bisnis jelek.', 'Greenblatt, Stock Market Genius') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (56, 6, 'REIT dan dividen', 'Mengapa REIT secara umum memberikan yield dividen lebih tinggi dari saham biasa?', '["Karena manajemennya lebih dermawan", "Regulasi mewajibkan distribusi minimal sembilan puluh persen pendapatan kena pajak", "REIT tidak perlu membayar pajak perusahaan"]'::jsonb, 'Regulasi mewajibkan distribusi minimal sembilan puluh persen pendapatan kena pajak', 'REIT wajib bagikan sebagian besar laba—itu menarik atau sekadar regulasi?', 'REIT diwajibkan mendistribusikan minimal sembilan puluh persen pendapatan kena pajak sehingga yield biasanya tinggi.', 'REIT adalah eksposur properti lewat bursa dengan distribusi besar namun harga tetap bergerak seperti saham biasa.', 'REIT: properti likuid, dividen relatif besar.', 'NAREIT REITs and Income Investing') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (57, 6, 'Kalender dividen', 'Syarat untuk berhak menerima dividen yang diumumkan adalah membeli saham sebelum tanggal apa?', '["Payment date", "Ex-dividend date", "Record date saja"]'::jsonb, 'Ex-dividend date', 'Beli sebelum record date—itu resep dapat dividen atau sudah terlambat?', 'Memahami ex-date, record date, dan payment date penting agar tahu kapan berhak atas dividen yang diumumkan.', 'Beli sebelum ex-date berhak dividen; beli saat atau setelah ex-date tidak mendapat dividen periode tersebut.', 'Tanggal menentukan siapa dapat dividen.', 'NYSE Dividend Timeline Guide') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (58, 6, 'Pajak dividen internasional', 'Apa yang perlu dihitung investor sebelum mengejar dividen dari saham asing?', '["Hanya yield gross-nya saja", "Tarif withholding tax dan return after-tax yang sebenarnya diterima", "Hanya kurs mata uang saja"]'::jsonb, 'Tarif withholding tax dan return after-tax yang sebenarnya diterima', 'Dividen saham AS kena withholding tax sebelum masuk rekening—berapa?', 'Negara sumber sering memungut pajak sebelum dividen dibayarkan ke investor asing dari negara berbeda.', 'Tarif withholding bervariasi antar negara dan perjanjian pajak; hitung return neto realistis untuk perbandingan wajar.', 'Hitung after-tax sebelum kejar dividen luar.', 'OECD Double Tax Treaty Database') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (59, 6, 'Dividen vs buyback', 'Buyback saham mengembalikan nilai ke pemegang saham dengan cara apa?', '["Mengirim uang tunai langsung ke rekening", "Mengurangi saham beredar sehingga nilai per lembar meningkat", "Memberikan saham bonus gratis"]'::jsonb, 'Mengurangi saham beredar sehingga nilai per lembar meningkat', 'Perusahaan beli kembali sahamnya sendiri daripada dividen—kamu untung juga?', 'Buyback mengembalikan uang ke investor lewat apresiasi harga per lembar bukan kas langsung ke rekening investor.', 'Buyback menurunkan saham beredar sehingga EPS naik; investor tidak langsung terima kas tapi nilai per lembar bertambah.', 'Buyback untung tersembunyi dari pandangan.', 'Warren Buffett, Berkshire Annual Letters') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (60, 6, 'Cakrawala dividend investing', 'Mengapa investor muda justru paling diuntungkan dari strategi dividend growth?', '["Karena mereka tidak perlu penghasilan dari portofolio sekarang", "Karena dividen selalu lebih besar untuk investor muda", "Karena pajak lebih rendah untuk pemula"]'::jsonb, 'Karena mereka tidak perlu penghasilan dari portofolio sekarang', 'Dividend investing hanya untuk pensiunan—benarkah?', 'Investor muda bisa membangun portofolio dividen yang berkembang kompaun jauh sebelum membutuhkan penghasilan darinya.', 'Panjang waktu memaksimalkan manfaat reinvestasi dividen; semakin panjang cakrawala semakin besar efek kompaun berlapis.', 'Tanam dividen muda, petik lebih besar.', 'Jeremy Siegel, Stocks for Long Run') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (61, 7, 'DeFi tanpa intermediari', 'Risiko utama yang tidak ada di perbankan tradisional namun ada di DeFi adalah?', '["Bunga yang terlalu rendah", "Kode smart contract yang bisa dieksploitasi tanpa perlindungan lembaga", "Persyaratan KYC yang ketat"]'::jsonb, 'Kode smart contract yang bisa dieksploitasi tanpa perlindungan lembaga', 'Pinjam uang tanpa bank dalam menit—itu aman?', 'DeFi mengganti intermediari keuangan dengan protokol kode yang berjalan otomatis di blockchain tanpa pihak ketiga.', 'Smart contract menjalankan layanan tanpa pihak tengah; kode bisa dieksploitasi dan tidak ada lembaga melindungi nasabah.', 'Tanpa intermediari berarti tanpa perlindungan juga.', 'Vitalik Buterin, Ethereum Whitepaper') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (62, 7, 'Bitcoin halving', 'Bitcoin halving memengaruhi ekosistem dengan cara apa?', '["Menggandakan jumlah Bitcoin beredar", "Mengurangi reward penambang setengahnya sehingga pasokan baru melambat", "Menaikkan biaya transaksi secara otomatis"]'::jsonb, 'Mengurangi reward penambang setengahnya sehingga pasokan baru melambat', 'Bitcoin reward dipotong setengah setiap empat tahun—sengaja diprogram?', 'Halving mengurangi reward penambang setengahnya setiap sekitar empat tahun, membatasi pasokan baru secara algoritma tetap.', 'Pasokan terbatas dua puluh satu juta dan penurunan penerbitan memengaruhi dinamika penawaran; permintaan menentukan harga.', 'Pasokan terbatas, permintaan tentukan harga.', 'Bitcoin Whitepaper Satoshi Nakamoto 2008') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (63, 7, 'Korelasi kripto dan pasar', 'Dalam kondisi krisis pasar, korelasi kripto dengan saham biasanya bagaimana?', '["Menjadi nol karena kripto independen", "Meningkat karena investor menjual berbagai aset bersamaan", "Turun menjadi negatif otomatis"]'::jsonb, 'Meningkat karena investor menjual berbagai aset bersamaan', 'Kripto katanya bebas pasar tradisional—kenapa ikut turun saat saham crash?', 'Saat likuiditas global ketat, investor menjual berbagai aset bersamaan termasuk kripto dan saham sekaligus.', 'Korelasi kripto ke saham meningkat di krisis; manfaat diversifikasi lebih terasa di kondisi pasar biasa saja.', 'Kripto bukan pelindung otomatis di krisis.', 'BIS Research Crypto Asset Correlations') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (64, 7, 'Risiko exchange terpusat', 'Menyimpan kripto di exchange terpusat menanggung risiko utama apa?', '["Nilai aset lebih stabil karena dijaga exchange", "Exchange bisa bangkrut atau dibekukan sehingga akses terhambat", "Biaya lebih mahal dari cold wallet"]'::jsonb, 'Exchange bisa bangkrut atau dibekukan sehingga akses terhambat', 'Kripto di exchange—itu benar-benar milikmu atau milik platform?', 'Menyimpan kripto di exchange berarti mempercayakan kunci privat ke pihak ketiga yang bisa gagal atau diblokir.', 'Exchange bangkrut atau dibekukan regulator bisa membekukan akses; not your keys not your coins berlaku nyata.', 'Kunci bukan milikmu, aset tak pasti.', 'FTX Collapse Congressional Testimony 2022') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (65, 7, 'Staking dan risiko reward', 'Risiko yang sering tidak disadari investor saat staking kripto adalah?', '["Reward selalu melebihi risiko harga", "Nilai token bisa turun lebih cepat dari akumulasi reward staking", "Tidak ada risiko sama sekali"]'::jsonb, 'Nilai token bisa turun lebih cepat dari akumulasi reward staking', 'Staking memberikan bunga dari kripto terkunci—itu deposito digital?', 'Staking mengamankan jaringan dan memberikan hadiah token; namun risiko slash dan penurunan harga token tetap nyata.', 'APY staking bisa tinggi tapi nilai token bisa turun lebih cepat dari akumulasi reward yang dijanjikan.', 'APY staking tinggi belum tentu menguntungkan.', 'Ethereum Foundation Proof of Stake Docs') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (66, 7, 'Layer 2 dan skalabilitas', 'Manfaat utama transaksi di layer 2 dibanding layer 1 Ethereum adalah?', '["Lebih aman dari layer 1", "Biaya lebih rendah dan kecepatan lebih tinggi dengan keamanan mengacu L1", "Tidak ada risiko sama sekali"]'::jsonb, 'Biaya lebih rendah dan kecepatan lebih tinggi dengan keamanan mengacu L1', 'Transaksi Ethereum sangat mahal—ada solusi tanpa ganti blockchain?', 'Layer 2 memproses transaksi di luar rantai utama dan menetap di blockchain utama secara periodik lebih efisien.', 'Biaya lebih rendah dan kecepatan lebih tinggi di L2; namun tergantung keamanan dan liveness bridge ke L1.', 'L2 lebih murah, tapi bridge ada risiko.', 'Optimism Arbitrum Technical Documentation') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (67, 7, 'Risiko regulasi kripto', 'Regulasi yang tiba-tiba melarang trading kripto di suatu negara paling langsung berdampak pada apa?', '["Kenaikan harga secara otomatis", "Pembatasan likuiditas dan kemampuan investor menjual aset", "Peningkatan keamanan jaringan"]'::jsonb, 'Pembatasan likuiditas dan kemampuan investor menjual aset', 'Negara larang trading kripto semalam—portofoliomu terdampak besok pagi?', 'Regulasi kripto berubah cepat dan bervariasi antar negara; ketidakpastian hukum adalah risiko nyata portofolio kripto.', 'Regulasi ketat bisa membatasi likuiditas, membekukan exchange lokal, dan memengaruhi harga secara signifikan.', 'Hukum bisa ubah likuiditas kripto tiba-tiba.', 'SEC MiCA EU Crypto Regulation') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (68, 7, 'Bitcoin sebagai inflasi hedge', 'Bukti historis tentang Bitcoin sebagai pagar inflasi menunjukkan apa?', '["Bitcoin selalu naik saat inflasi tinggi", "Korelasi ke aset risiko lebih kuat dari korelasi ke inflasi aktual", "Bitcoin terbukti sempurna sebagai lindung nilai"]'::jsonb, 'Korelasi ke aset risiko lebih kuat dari korelasi ke inflasi aktual', 'Bitcoin disebut pagar inflasi—tapi 2022 inflasi tinggi dan Bitcoin turun besar?', 'Narasi Bitcoin sebagai lindung nilai inflasi belum terbukti konsisten dalam sejarah singkatnya yang baru beberapa siklus.', 'Korelasi ke aset risiko lebih kuat dari korelasi ke inflasi aktual; narasi berbeda dari data historis.', 'Inflasi hedge kripto: narasi lebih dari bukti.', 'NY Fed Crypto Inflation Hedge Paper') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (69, 7, 'Altcoin vs Bitcoin', 'Mengapa mayoritas altcoin kehilangan nilai lebih dari sembilan puluh persen dari puncaknya?', '["Karena regulasi melarang semua altcoin", "Bergantung pada narasi dan likuiditas siklus tanpa efek jaringan kuat", "Karena pajaknya lebih tinggi dari Bitcoin"]'::jsonb, 'Bergantung pada narasi dan likuiditas siklus tanpa efek jaringan kuat', 'Altcoin janji teknologi lebih canggih dari Bitcoin—kenapa mayoritas mati?', 'Ribuan altcoin muncul setiap siklus bull; mayoritas kehilangan nilai lebih dari sembilan puluh persen saat siklus berakhir.', 'Altcoin sering bergantung narasi dan likuiditas siklus; Bitcoin memiliki efek jaringan dan adopsi lebih kuat.', 'Altcoin banyak, yang bertahan sangat sedikit.', 'CoinGecko Market Data Report 2023') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (70, 7, 'NFT dan valuasi', 'Risiko fundamental berinvestasi di NFT dibanding saham adalah?', '["NFT selalu lebih likuid dari saham", "Tidak ada arus kas underlying; valuasi murni berbasis sentimen komunitas", "NFT diregulasi lebih ketat dari saham"]'::jsonb, 'Tidak ada arus kas underlying; valuasi murni berbasis sentimen komunitas', 'Gambar dijual satu miliar—kenapa orang mau bayar itu untuk JPEG?', 'Nilai NFT bergantung persepsi komunitas, kelangkaan digital, dan momentum spekulasi yang bisa hilang sangat cepat.', 'Tidak ada arus kas underlying; valuasi murni berbasis sentimen dan status sosial di komunitas tertentu saja.', 'Nilai NFT hanya ada jika dipercaya.', 'Chainalysis NFT Market Report 2022') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (71, 8, 'Quantitative easing', 'Quantitative easing bank sentral bekerja dengan cara apa?', '["Mencetak uang dan membagikannya langsung ke masyarakat", "Membeli obligasi untuk menekan yield dan mendorong kredit", "Menaikkan suku bunga acuan"]'::jsonb, 'Membeli obligasi untuk menekan yield dan mendorong kredit', 'Bank sentral beli obligasi triliunan—itu inflasi langsung atau lebih rumit?', 'QE meningkatkan cadangan bank dan memengaruhi suku jangka panjang lewat pembelian obligasi skala masif.', 'QE menekan yield obligasi mendorong investor ke aset berisiko; efek inflasi bergantung kecepatan transmisi kredit.', 'Cetak uang tidak langsung berarti inflasi.', 'Federal Reserve QE Programs Explained') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (72, 8, 'Siklus kredit', 'Perusahaan leverage tinggi paling rentan di fase apa dari siklus kredit?', '["Saat kredit murah dan mudah didapat", "Saat suku naik dan kondisi kredit mengencang", "Saat pasar saham sedang naik"]'::jsonb, 'Saat suku naik dan kondisi kredit mengencang', 'Perusahaan berutang banyak saat kredit murah—masalahnya datang kapan?', 'Siklus kredit bergantian ekspansi dan kontraksi; puncak dan lembah mempengaruhi investasi bisnis secara signifikan.', 'Saat bunga naik dan kredit ketat, perusahaan leverage tinggi menanggung beban keuangan yang paling berat.', 'Utang murah hari ini bisa mahal nanti.', 'Hyman Minsky Financial Instability') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (73, 8, 'PMI sebagai sinyal ekonomi', 'Angka PMI di bawah lima puluh mengindikasikan apa secara ekonomi?', '["Ekspansi aktivitas bisnis", "Kontraksi sektor yang disurvei", "Inflasi meningkat dengan cepat"]'::jsonb, 'Kontraksi sektor yang disurvei', 'PMI keluar di bawah lima puluh—ekonomi mau kontraksi atau hanya noise?', 'PMI mengukur kondisi manufaktur atau jasa dari survei manajer pembelian secara bulanan secara sistematis.', 'Di atas lima puluh berarti ekspansi; di bawah kontraksi. Konfirmasi butuh beberapa bulan data yang konsisten.', 'PMI di bawah lima puluh, waspada sinyal.', 'ISM PMI Monthly Report USA') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (74, 8, 'Indeks dolar dan pasar berkembang', 'Penguatan dolar AS paling langsung membebani negara berkembang dalam hal apa?', '["Ekspor mereka menjadi lebih mahal", "Utang berdenominasi dolar jadi lebih mahal dalam mata uang lokal", "Inflasi domestik langsung turun"]'::jsonb, 'Utang berdenominasi dolar jadi lebih mahal dalam mata uang lokal', 'DXY naik tajam—kenapa aset negara berkembang ikut terguncang?', 'Dolar kuat menekan komoditas berdenominasi dolar dan membebani negara berutang dalam mata uang asing.', 'Banyak utang negara berkembang dalam dolar; penguatan DXY meningkatkan beban riil utang dalam mata uang lokal.', 'Dolar kuat, beban utang asing berat.', 'IMF Global Financial Stability Report') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (75, 8, 'Siklus super komoditas', 'Siklus super komoditas berlangsung lama karena alasan apa?', '["Regulasi pemerintah yang lambat", "Keterlambatan respons pasokan dari penambangan dan produksi baru", "Konsumen tidak tertarik pada komoditas"]'::jsonb, 'Keterlambatan respons pasokan dari penambangan dan produksi baru', 'Komoditas naik satu dekade, terpuruk satu dekade—pola atau kebetulan?', 'Siklus super komoditas didorong pertumbuhan besar ekonomi industri yang membutuhkan sumber daya dalam jumlah besar.', 'Siklus berlangsung lama karena keterlambatan pasokan; investasi tambang besar diperlukan sebelum output baru keluar.', 'Komoditas butuh waktu pasokan merespons.', 'Commodity Research Bureau Data') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (76, 8, 'Risiko pasar berkembang', 'Risiko spesifik yang tidak ada di pasar maju namun umum di emerging market adalah?', '["Volatilitas harga saham", "Risiko kontrol modal dan ketidakstabilan politik yang memotong return", "Risiko bunga yang tinggi"]'::jsonb, 'Risiko kontrol modal dan ketidakstabilan politik yang memotong return', 'Pertumbuhan tinggi dan imbal besar—kenapa banyak yang masih ragu EM?', 'Pasar berkembang menawarkan potensi lebih tapi menghadapi risiko politik, mata uang, dan regulasi lebih besar.', 'Risiko spesifik negara seperti kontrol modal dan ketidakstabilan politik dapat memotong return investor asing secara tiba-tiba.', 'Return EM besar, risiko politiknya nyata.', 'MSCI Emerging Market Index Guide') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (77, 8, 'Suku bunga riil negatif', 'Suku bunga riil negatif artinya apa bagi penabung?', '["Daya beli tabungan tumbuh seiring waktu", "Daya beli tabungan tergerus meski nominal positif", "Tidak ada dampak pada nilai uang"]'::jsonb, 'Daya beli tabungan tergerus meski nominal positif', 'Suku bunga enam persen terasa menarik—tapi kalau inflasi delapan persen?', 'Suku bunga riil negatif menggerus nilai simpanan meski nominal terlihat positif dan rekening tidak berkurang angkanya.', 'Investasi harus setidaknya mengalahkan inflasi untuk menjaga daya beli; suku riil negatif memaksa cari return lebih.', 'Suku riil negatif, tabungan perlahan rusak.', 'BIS Working Paper Real Rates') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (78, 8, 'Stress test perbankan', 'Tujuan utama stress test bank yang dilakukan regulator adalah?', '["Menentukan dividen bank yang boleh dibayarkan", "Mengukur ketahanan modal bank terhadap skenario ekonomi ekstrem", "Menghitung gaji eksekutif bank"]'::jsonb, 'Mengukur ketahanan modal bank terhadap skenario ekstrem', 'Bank disimulasikan krisis parah oleh regulator—lulus berarti aman sepenuhnya?', 'Stress test mengukur ketahanan modal bank terhadap skenario ekonomi ekstrem yang ditentukan regulator secara periodik.', 'Lulus stress test menurunkan kemungkinan gagal; namun skenario tidak bisa meramalkan setiap kondisi ekstrem nyata.', 'Lulus test bukan jaminan semua skenario.', 'Fed Reserve DFAST Annual Report') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (79, 8, 'Defisit fiskal dan pasar', 'Defisit fiskal yang terlalu besar berpotensi memengaruhi pasar obligasi dengan cara apa?', '["Menurunkan yield obligasi secara otomatis", "Menekan kepercayaan dan menaikkan biaya pinjaman negara", "Membuat saham selalu naik"]'::jsonb, 'Menekan kepercayaan dan menaikkan biaya pinjaman negara', 'Pemerintah belanja lebih dari pajak—utang negara masalah kapan?', 'Defisit fiskal dalam batas dapat mendorong pertumbuhan; berlebihan menekan kepercayaan dan menaikkan biaya pinjaman.', 'Keberlangsungan fiskal bergantung pertumbuhan GDP vs beban bunga; debt-to-GDP adalah rasio yang diperhatikan pasar obligasi.', 'Defisit masalah saat bunga melebihi tumbuh.', 'IMF Fiscal Monitor Report') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (80, 8, 'Siklus panjang ekonomi', 'Mengapa siklus ekonomi jangka panjang kurang berguna untuk keputusan investasi praktis?', '["Karena siklus tidak pernah terjadi", "Terlalu panjang dan tidak presisi untuk keputusan jangka menengah", "Karena tidak ada data historinya"]'::jsonb, 'Terlalu panjang dan tidak presisi untuk keputusan jangka menengah', 'Ada teori siklus ekonomi lima puluh tahun—terlalu panjang untuk praktis?', 'Siklus panjang menggambarkan gelombang inovasi dan depresi yang berlangsung beberapa dekade penuh secara berulang.', 'Berguna sebagai kerangka sejarah makro; tidak cukup presisi untuk keputusan investasi jangka menengah yang konkret.', 'Siklus panjang: kerangka bukan ramalan harian.', 'Kondratieff Long Wave Theory') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (81, 9, 'Core-satellite portofolio', 'Pendekatan core-satellite menggabungkan apa?', '["Semua saham aktif tanpa indeks", "Fondasi indeks pasif murah dengan ekspresi aktif kecil", "Hanya obligasi dan kas"]'::jsonb, 'Fondasi indeks pasif murah dengan ekspresi aktif kecil', 'Satu ETF indeks untuk sebagian besar portofolio dan saham pilih sedikit—mungkin?', 'Core-satellite menggabungkan fondasi pasif murah dengan ekspresi aktif terbatas untuk alpha tanpa buang biaya besar.', 'Core biasanya tujuh puluh sampai sembilan puluh persen; satellite mengambil risiko spesifik dengan posisi yang dibatasi.', 'Fondasi pasif, ekspresi aktif terbatas.', 'Ibbotson Associates Core Satellite') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (82, 9, 'Risk parity', 'Risk parity mengalokasikan berdasarkan apa?', '["Berdasarkan nilai absolut tiap aset", "Berdasarkan kontribusi volatilitas setiap aset ke portofolio", "Berdasarkan popularitas di pasar"]'::jsonb, 'Berdasarkan kontribusi volatilitas setiap aset ke portofolio', 'Alokasi berdasarkan risiko bukan nilai—lebih adil atau lebih rumit?', 'Risk parity mengalokasikan modal berdasarkan kontribusi volatilitas setiap aset ke portofolio secara keseluruhan.', 'Aset volatilitas tinggi mendapat bobot lebih kecil sehingga risiko berkontribusi merata; sering butuh leverage obligasi.', 'Alokasikan risiko, bukan hanya modal.', 'Bridgewater All Weather Strategy') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (83, 9, 'Aset alternatif', 'Manfaat utama memasukkan aset alternatif ke portofolio adalah?', '["Selalu memberikan return lebih tinggi dari saham", "Korelasi lebih rendah ke pasar publik menambah diversifikasi", "Likuiditas lebih tinggi dari saham"]'::jsonb, 'Korelasi lebih rendah ke pasar publik menambah diversifikasi', 'Saham, obligasi—sudah. Apa lagi yang bisa masuk portofolio?', 'Aset alternatif seperti properti, komoditas, dan private equity dapat menambah sumber return yang berbeda.', 'Korelasi lebih rendah ke pasar publik memberikan diversifikasi tambahan; likuiditas dan biaya sering lebih tinggi.', 'Alternatif: diversifikasi lebih dalam, likuiditas kurang.', 'Yale Endowment Model David Swensen') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (84, 9, '60/40 di era inflasi', 'Mengapa alokasi 60/40 kehilangan efektivitas di lingkungan inflasi tinggi?', '["Karena saham terlalu murah", "Korelasi positif saham dan obligasi melemahkan manfaat diversifikasi", "Karena obligasi memberikan return lebih tinggi dari saham"]'::jsonb, 'Korelasi positif saham dan obligasi melemahkan manfaat diversifikasi', 'Obligasi tidak lagi lindungi saham saat dua-duanya turun 2022—60/40 masih valid?', 'Korelasi positif saham dan obligasi di inflasi tinggi melemahkan manfaat diversifikasi 60/40 tradisional secara signifikan.', '60/40 bekerja baik saat inflasi rendah; lingkungan berbeda butuh evaluasi ulang dan penambahan kelas aset lain.', '60/40 bukan dogma, baca kondisinya.', 'Research Affiliates 60/40 Dead Paper') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (85, 9, 'Barbell strategy', 'Barbell strategy dalam portofolio berarti apa secara alokasi?', '["Semua di tengah untuk keseimbangan", "Konsentrasi di dua ekstrem: sangat aman dan sangat spekulatif", "Semua di saham pertumbuhan saja"]'::jsonb, 'Konsentrasi di dua ekstrem: sangat aman dan sangat spekulatif', 'Semua aman atau semua spekulatif tanpa tengah—itu strategi?', 'Barbell mengalokasikan ke dua ekstrem: sangat konservatif dan sangat agresif, dengan sedikit atau tidak di tengah.', 'Aset aman melindungi dari kerugian besar; aset spekulatif kecil memberikan potensi return asimetris yang besar.', 'Ekstrem dua sisi, hindari tengah meragukan.', 'Nassim Taleb, Antifragile') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (86, 9, 'Tax loss harvesting', 'Tax loss harvesting mengoptimalkan pajak dengan cara apa?', '["Menghindari semua pajak capital gain selamanya", "Mengkristalisasi kerugian untuk mengimbangi capital gain kena pajak di tahun yang sama", "Hanya berlaku untuk obligasi pemerintah"]'::jsonb, 'Mengkristalisasi kerugian untuk mengimbangi capital gain kena pajak di tahun yang sama', 'Posisi merah bisa berguna di akhir tahun—bukan rugi, tapi pajak?', 'Kristalisasi rugi untuk mengimbangi capital gain kena pajak di tahun yang sama secara legal dan terencana.', 'Rugi terealisasi mengurangi pajak gain; aset bisa dibeli kembali setelah wash sale period sesuai aturan berlaku.', 'Rugi pun bisa dikelola jadi manfaat.', 'IRS Publication 550 Investment Income') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (87, 9, 'Peran kas dalam portofolio', 'Mengapa menyisihkan kas dalam portofolio memiliki nilai strategis?', '["Kas selalu memberikan return tertinggi", "Kas memberikan fleksibilitas mengambil peluang dan meredam volatilitas", "Kas tidak berperan dalam portofolio"]'::jsonb, 'Kas memberikan fleksibilitas mengambil peluang dan meredam volatilitas', 'Semua diinvestasikan—keren. Tapi saat peluang muncul, ada amunisi?', 'Menyisihkan kas memberi fleksibilitas mengambil peluang dan meredam volatilitas portofolio saat pasar bergejolak.', 'Kas adalah aset return rendah tapi opsi tinggi; berguna saat pasar crash memberikan harga menarik untuk dibeli.', 'Kas kering siap tembak peluang.', 'Howard Marks Mastering Market Cycle') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (88, 9, 'Konsentrasi vs diversifikasi', 'Kapan strategi konsentrasi portofolio masuk akal?', '["Selalu lebih baik dari diversifikasi", "Ketika investor memiliki keunggulan informasi atau analisis yang terverifikasi", "Bagi semua investor pemula"]'::jsonb, 'Ketika investor memiliki keunggulan informasi atau analisis yang terverifikasi', 'Buffett bilang diversifikasi untuk yang tidak tahu—mana yang benar untukmu?', 'Diversifikasi melindungi dari ketidaktahuan; konsentrasi memaksimalkan potensi tapi memperbesar risiko salah secara besar.', 'Investor tanpa keunggulan informasi sebaiknya diversifikasi luas; konsentrasi masuk akal dengan keunggulan nyata terverifikasi.', 'Punya edge nyata? Konsentrasi masuk akal.', 'Charlie Munger Poor Charlies Almanack') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (89, 9, 'Portable alpha', 'Konsep portable alpha bertujuan memisahkan apa dalam manajemen portofolio?', '["Antara saham dan obligasi saja", "Antara eksposur beta pasar dari upaya menghasilkan alpha tambahan", "Antara investasi lokal dan global"]'::jsonb, 'Antara eksposur beta pasar dari upaya menghasilkan alpha tambahan', 'Beta ambil dari indeks murah, alpha cari dari strategi lain—bisa dipisahkan?', 'Portable alpha memisahkan eksposur pasar dari usaha menghasilkan return lebih dari benchmark indeks secara sistematis.', 'Gunakan instrumen murah untuk beta pasar; tambahkan strategi alpha terpisah yang tidak berkorelasi ke aset utama.', 'Beta murah, alpha cari di tempat lain.', 'PIMCO Portable Alpha Strategy Paper') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (90, 9, 'Ulasan portofolio berkala', 'Frekuensi ulasan portofolio yang ideal menghindari dua masalah apa?', '["Hanya satu masalah: terlalu jarang melihat", "Reaksi emosional terlalu sering dan drift risiko karena terlalu jarang", "Hanya masalah pajak saja"]'::jsonb, 'Reaksi emosional terlalu sering dan drift risiko karena terlalu jarang', 'Tidak pernah buka portofolio setahun—itu disiplin atau lalai?', 'Ulasan berkala memastikan alokasi masih sesuai tujuan; terlalu sering memicu emosi, terlalu jarang membiarkan drift.', 'Terlalu sering memicu reaksi emosional; terlalu jarang membiarkan drift besar tak disadari dari profil risiko awal.', 'Tinjau berkala, bukan reaktif harian.', 'Vanguard Investor Behavior Research') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (91, 10, 'Availability heuristic', 'Availability heuristic menyebabkan orang melebih-lebihkan risiko apa?', '["Risiko yang jarang terjadi tapi mudah diingat karena dramatis", "Risiko yang sering terjadi secara statistik", "Risiko yang sudah dihitung datanya"]'::jsonb, 'Risiko yang jarang terjadi tapi mudah diingat karena dramatis', 'Baca berita kecelakaan pesawat—mendadak takut terbang padahal datanya bagaimana?', 'Otak menilai probabilitas berdasarkan seberapa mudah contoh terlintas di kepala bukan data aktual yang tersedia.', 'Berita negatif mudah diingat sehingga otak melebih-lebihkan risiko peristiwa dramatis dan meremehkan risiko biasa.', 'Mudah teringat bukan berarti sering terjadi.', 'Tversky Kahneman Heuristics and Biases') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (92, 10, 'Representativeness bias', 'Representativeness bias menyebabkan investor melakukan kesalahan apa?', '["Selalu membeli saham murah", "Menilai saham bagus dari kualitas perusahaan tanpa memperhitungkan harga", "Menghindari semua risiko secara berlebihan"]'::jsonb, 'Menilai saham bagus dari kualitas perusahaan tanpa memperhitungkan harga', 'Perusahaan bagus berarti saham bagus—kenapa sering tidak sesederhana itu?', 'Kita menilai saham berdasarkan kualitas perusahaan tanpa mempertimbangkan apakah harga sudah mencerminkannya.', 'Bisnis hebat bisa jadi investasi buruk jika sudah dibayar terlalu mahal di harga pasar saat ini.', 'Perusahaan bagus bukan otomatis saham bagus.', 'Kahneman Thinking Fast and Slow') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (93, 10, 'Sunk cost dalam investasi', 'Sunk cost fallacy dalam investasi paling sering mendorong perilaku apa?', '["Menjual posisi merah dengan cepat", "Mempertahankan posisi buruk demi menghindari rasa menyesal kristalisasi kerugian", "Mendiversifikasi portofolio lebih luas"]'::jsonb, 'Mempertahankan posisi buruk demi menghindari rasa menyesal kristalisasi kerugian', 'Sudah rugi dua puluh persen—itu alasan untuk terus pegang?', 'Uang yang sudah hilang tidak bisa kembali; keputusan harus berdasarkan prospek masa depan bukan masa lalu.', 'Sunk cost fallacy membuat investor mempertahankan posisi buruk demi menghindari rasa menyesal kristalisasi kerugian.', 'Masa lalu tidak menentukan keputusan kini.', 'Arkes Blumer Sunk Cost Research') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (94, 10, 'Gambler''s fallacy', 'Gambler''s fallacy membuat investor percaya apa yang salah?', '["Pasar selalu naik dalam jangka panjang", "Setelah tren panjang ke satu arah, pasar harus berbalik", "Diversifikasi selalu menurunkan return"]'::jsonb, 'Setelah tren panjang ke satu arah, pasar harus berbalik', 'Saham turun lima hari berturut—harus naik besok, kan waktunya?', 'Otak menciptakan pola dari rangkaian acak dan percaya arah harus berbalik setelah rangkaian panjang terjadi.', 'Pasar tidak ingat masa lalu; setiap hari atau transaksi independen dari tren sebelumnya secara probabilitas.', 'Pasar tidak berhutang pembalikan.', 'Tversky Gambler Fallacy Study') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (95, 10, 'Status quo bias investasi', 'Status quo bias dalam portofolio paling berbahaya ketika apa?', '["Saat pasar sedang naik", "Portofolio tidak pernah disesuaikan meski tujuan atau kondisi berubah", "Saat investor baru mulai berinvestasi"]'::jsonb, 'Portofolio tidak pernah disesuaikan meski tujuan atau kondisi berubah', 'Portofolio tidak pernah diubah sejak dibeli—keyakinan atau kemalasan?', 'Kecenderungan mempertahankan kondisi sekarang menghalangi penyesuaian portofolio yang sebenarnya diperlukan seiring waktu.', 'Status quo bias membuat investor gagal rebalancing tepat waktu atau memangkas posisi yang sudah tidak relevan.', 'Diam bisa membiarkan masalah tumbuh.', 'Samuelson Zeckhauser Status Quo Study') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (96, 10, 'Ilusi kontrol', 'Ilusi kontrol dalam investasi paling sering mendorong apa?', '["Diversifikasi lebih luas dari yang diperlukan", "Kepercayaan berlebihan bahwa analisis mendalam menghilangkan ketidakpastian", "Keengganan mengambil risiko sama sekali"]'::jsonb, 'Kepercayaan berlebihan bahwa analisis mendalam menghilangkan ketidakpastian', 'Sering analisis sendiri—pasti lebih baik hasilnya dari yang tidak?', 'Banyak investor percaya pengetahuan mereka memberikan kontrol lebih atas hasil yang sebenarnya tidak terkontrol.', 'Riset baik menurunkan risiko tapi tidak menghapus ketidakpastian; pasar mengandung elemen acak yang tidak bisa dikendalikan.', 'Riset baik mengurangi bukan menghapus risiko.', 'Langer Illusion of Control Study') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (97, 10, 'Narrative fallacy', 'Narrative fallacy dalam investasi mendorong perilaku apa?', '["Selalu mengandalkan data kuantitatif", "Membeli cerita menarik tanpa menguji data yang mendasarinya", "Menghindari semua investasi berisiko"]'::jsonb, 'Membeli cerita menarik tanpa menguji data yang mendasarinya', 'Cerita bagus tentang perusahaan baru—sudah cukup untuk investasi?', 'Kita menyukai narasi yang masuk akal dan sering membeli cerita daripada menguji data yang memverifikasinya.', 'Kisah menarik dapat menutupi kelemahan fundamental; data harus mengonfirmasi narasi sebelum mengambil posisi nyata.', 'Cerita menarik perlu didukung angka nyata.', 'Nassim Taleb The Black Swan') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (98, 10, 'Authority bias', 'Authority bias dalam investasi mendorong investor melakukan apa yang berbahaya?', '["Melakukan riset lebih mendalam", "Mengikuti rekomendasi otoritas tanpa evaluasi mandiri", "Membeli saham defensif saja"]'::jsonb, 'Mengikuti rekomendasi otoritas tanpa evaluasi mandiri', 'Analis terkenal merekomendasikan beli—cukup tanpa pertimbangan sendiri?', 'Kepercayaan berlebihan pada otoritas finansial mengikis kemampuan berpikir kritis investor dalam mengambil keputusan.', 'Pakar bisa salah; evaluasi rekomendasi dengan logika dan data sendiri sebelum bertindak adalah kewajiban investor.', 'Pakar bisa salah, pikir sendiri juga.', 'Cialdini Authority and Influence') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (99, 10, 'Social proof di pasar', 'Saat semua orang ramai membeli satu aset, apa yang sering terjadi pada harganya?', '["Harga pasti akan terus naik lebih lanjut", "Harga kemungkinan sudah mahal dan prospek terharga", "Harga selalu tetap stabil setelah viral"]'::jsonb, 'Harga kemungkinan sudah mahal dan prospek terharga', 'Semua orang beli aset ini—pasti ada yang mereka tahu aku belum?', 'Bukti sosial kuat dalam investasi; ramai membeli sering justru tanda harga sudah mencerminkan banyak optimisme.', 'Ketika semua sepakat, prospek mungkin sudah terharga; keramaian beli sering mendahului koreksi besar di pasar.', 'Semua sepakat beli? Tanya harga dulu.', 'Kindleberger Manias Panics Crashes') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight, source_reference) VALUES (100, 10, 'Optimism bias', 'Optimism bias dalam proyeksi investasi paling sering menyebabkan apa?', '["Diversifikasi yang berlebihan", "Kurang mempersiapkan skenario buruk dan leverage berlebihan", "Selalu memilih instrumen konservatif"]'::jsonb, 'Kurang mempersiapkan skenario buruk dan leverage berlebihan', 'Semua proyeksi portofolio selalu memperkirakan naik—apa yang sering dilupakan?', 'Otak cenderung memperkirakan hasil lebih baik dari probabilitas wajar tanpa penyesuaian risiko yang realistis.', 'Optimisme berlebihan mendorong kurang diversifikasi, leverage berlebihan, dan tidak siap menghadapi skenario buruk yang mungkin.', 'Proyeksi optimis butuh skenario buruk juga.', 'Weinstein Unrealistic Optimism Research') ON CONFLICT (id) DO NOTHING;
